    function ensureOtherLast(list) {
        const result = [];
        (list || []).forEach((item) => {
            if (!item || item === "أخرى") return;
            if (!result.includes(item)) result.push(item);
        });
        result.push("أخرى");
        return result;
    }

    function mergeLists(oldList, newList) {
        const merged = [];
        [...(oldList || []), ...(newList || [])].forEach((item) => {
            if (!item || item === "أخرى") return;
            if (!merged.includes(item)) merged.push(item);
        });
        merged.push("أخرى");
        return merged;
    }

    function reorderMathMain(currentList, desiredOrder) {
        const normalized = [];
        (currentList || []).forEach((item) => {
            if (!item || item === "أخرى") return;
            if (!normalized.includes(item)) normalized.push(item);
        });
        if (!normalized.includes(mainCategory)) normalized.push(mainCategory);

        const ordered = [];
        (desiredOrder || []).forEach((item) => {
            if (!item || item === "أخرى") return;
            if (normalized.includes(item) && !ordered.includes(item)) ordered.push(item);
        });
        normalized.forEach((item) => {
            if (!ordered.includes(item)) ordered.push(item);
        });
        ordered.push("أخرى");
        return ordered;
    }

